mapper.select:
select * from exp_reimbursement
where del_flag = '0'
and reimburse_no like concat('%', #{reimburseNo}, '%')
and proj_id = #{projId}
and node_id = #{nodeId}
and category_id = #{categoryId}
and expense_type = #{expenseType}
and status = #{status}
and expense_date >= #{beginExpenseDate}
and expense_date <= #{endExpenseDate}
order by create_time desc, reimburse_id desc

mapper.update:
update exp_reimbursement
set reimburse_no=#{reimburseNo}, proj_id=#{projId}, proj_name=#{projName}, node_id=#{nodeId}, node_name=#{nodeName}, category_id=#{categoryId}, category_name=#{categoryName}, expense_type=#{expenseType}, expense_date=#{expenseDate}, amount=#{amount}, expense_desc=#{expenseDesc}, invoice_count=#{invoiceCount}, status=#{status}, submit_time=#{submitTime}, approve_by=#{approveBy}, approve_time=#{approveTime}, reject_reason=#{rejectReason}, update_by=#{updateBy}, update_time=now(), remark=#{remark}
where reimburse_id=#{reimburseId}
